function formatDuration(s) {
  if (s == null) return '--';
  const h = Math.floor(s / 3600);
  const m = Math.floor((s % 3600) / 60);
  const sec = s % 60;
  if (h > 0) return h + 'h ' + String(m).padStart(2,'0') + 'm';
  return String(m).padStart(2,'0') + 'm ' + String(sec).padStart(2,'0') + 's';
}

function haversineMeters(lat1, lon1, lat2, lon2) {
  const R = 6371000;
  const toRad = function(d) { return d * Math.PI / 180; };
  const dLat = toRad(lat2 - lat1);
  const dLon = toRad(lon2 - lon1);
  const a = Math.sin(dLat/2)*Math.sin(dLat/2) + Math.cos(toRad(lat1))*Math.cos(toRad(lat2))*Math.sin(dLon/2)*Math.sin(dLon/2);
  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
}

function findMatchingAddress(lat, lon, addressRaw, savedAddresses) {
  if (lat != null && lon != null) {
    for (let i = 0; i < savedAddresses.length; i++) {
      const addr = savedAddresses[i];
      if (addr.latitude && addr.longitude) {
        const dist = haversineMeters(lat, lon, addr.latitude, addr.longitude);
        if (dist <= (addr.radius_meters || 200)) return addr;
      }
    }
  }
  const raw = (addressRaw || '').toLowerCase().trim();
  return savedAddresses.find(function(a) { return (a.formatted_address || '').toLowerCase().trim() === raw; }) || null;
}

function toLocalDateString(epochMs) {
  return new Date(epochMs).toLocaleDateString('en-US', {
    timeZone: FLEET_TIMEZONE, year: 'numeric', month: '2-digit', day: '2-digit'
  });
}

function toLocalTimeString(epochMs) {
  return new Date(epochMs).toLocaleTimeString('en-US', {
    timeZone: FLEET_TIMEZONE, hour: 'numeric', minute: '2-digit', hour12: true
  });
}

const vehicles = qRunReport.data || [];
const addresses = (qGetAddresses.data.data || []).map(function(a) {
  return {
    id: a.id,
    name: a.name,
    formatted_address: a.formattedAddress,
    latitude: a.latitude,
    longitude: a.longitude,
    radius_meters: (a.geofence && a.geofence.circle && a.geofence.circle.radius) || 200
  };
});

const rows = [];

for (let vi = 0; vi < vehicles.length; vi++) {
  const vehicle = vehicles[vi];
  const vehicleName = vehicle.vehicleName || vehicle.vehicleId;
  const vehicleVin = vehicle.vehicleVin || '';

  const trips = (vehicle.trips || []).map(function(t) {
    return {
      id: t.id,
